export function toTranslationsRequestCborValue(v: TranslationsRequest): CborValue {
  const csilMap = new Map<CborValue, CborValue>();
  if (v.locale !== undefined) csilMap.set("locale", v.locale);
  if (v.acceptLanguage !== undefined) csilMap.set("accept_language", v.acceptLanguage);
  return csilMap;
}

export function fromTranslationsRequestCborValue(value: CborValue): TranslationsRequest {
  return {
    locale: ((csilV: CborValue | undefined) => csilV === undefined ? undefined : asString(csilV))(mapGet(value, "locale")),
    acceptLanguage: ((csilV: CborValue | undefined) => csilV === undefined ? undefined : asString(csilV))(mapGet(value, "accept_language")),
  };
}

export function toTranslationsRequestCbor(v: TranslationsRequest): Uint8Array {
  return encodeValue(toTranslationsRequestCborValue(v));
}

export function fromTranslationsRequestCbor(bytes: Uint8Array): TranslationsRequest {
  return fromTranslationsRequestCborValue(decode(bytes));
}

export function toTranslationsResponseCborValue(v: TranslationsResponse): CborValue {
  const csilMap = new Map<CborValue, CborValue>();
  csilMap.set("locale", v.locale);
  csilMap.set("messages", new Map<CborValue, CborValue>(Object.entries(v.messages).map(([csilK, csilV]): [CborValue, CborValue] => [csilK, csilV])));
  csilMap.set("available_locales", v.availableLocales);
  return csilMap;
}

export function fromTranslationsResponseCborValue(value: CborValue): TranslationsResponse {
  return {
    locale: asString(requireKey(value, "locale")),
    availableLocales: asArray(requireKey(value, "available_locales")).map((csilE) => asString(csilE)),
    messages: Object.fromEntries(Array.from(asMap(requireKey(value, "messages")), ([csilK, csilV]): [string, string] => [asString(csilK), asString(csilV)])),
  };
}

export function toTranslationsResponseCbor(v: TranslationsResponse): Uint8Array {
  return encodeValue(toTranslationsResponseCborValue(v));
}

export function fromTranslationsResponseCbor(bytes: Uint8Array): TranslationsResponse {
  return fromTranslationsResponseCborValue(decode(bytes));
}

